import java.util.PriorityQueue

fun solve(grid: Array<Array<Long>>, k: Long): Long {
    val m = grid.size
    val n = grid[0].size
    val INF = 1_000_000_000_000_000_000L 
    val kInt = k.toInt()
    val dp = Array(m) { Array(n) { LongArray(kInt + 1) { INF } } }
    dp[0][0][0] = 0

    val MAX_VAL = 10000
    var bestMinCost_prev: LongArray? = null

    for (t in 0..kInt) {
        if (t >= 1) {
            for (i in 0 until m) {
                for (j in 0 until n) {
                    val v = minOf(grid[i][j], MAX_VAL.toLong()).toInt()
                    if (v in 0..MAX_VAL) {
                        val candidate = bestMinCost_prev!![v]
                        if (candidate < dp[i][j][t]) {
                            dp[i][j][t] = candidate
                        }
                    }
                }
            }
        }

        val heap = PriorityQueue<Pair<Long, Pair<Int, Int>>>(compareBy { it.first })
        for (i in 0 until m) {
            for (j in 0 until n) {
                if (dp[i][j][t] < INF) {
                    heap.offer(Pair(dp[i][j][t], Pair(i, j)))
                }
            }
        }

        while (heap.isNotEmpty()) {
            val (cost, cell) = heap.poll()
            val (i, j) = cell
            if (cost != dp[i][j][t]) continue

            if (j + 1 < n) {
                val ni = i
                val nj = j + 1
                val nCost = cost + grid[ni][nj]
                if (nCost < dp[ni][nj][t]) {
                    dp[ni][nj][t] = nCost
                    heap.offer(Pair(nCost, Pair(ni, nj)))
                }
            }

            if (i + 1 < m) {
                val ni = i + 1
                val nj = j
                val nCost = cost + grid[ni][nj]
                if (nCost < dp[ni][nj][t]) {
                    dp[ni][nj][t] = nCost
                    heap.offer(Pair(nCost, Pair(ni, nj)))
                }
            }
        }

        if (t < kInt) {
            val minCostForValue = LongArray(MAX_VAL + 1) { INF }
            for (i in 0 until m) {
                for (j in 0 until n) {
                    val v = minOf(grid[i][j], MAX_VAL.toLong()).toInt()
                    if (v in 0..MAX_VAL && dp[i][j][t] < minCostForValue[v]) {
                        minCostForValue[v] = dp[i][j][t]
                    }
                }
            }
            val bestMinCost_t = LongArray(MAX_VAL + 2) { INF }
            bestMinCost_t[MAX_VAL] = minCostForValue[MAX_VAL]
            for (v in MAX_VAL - 1 downTo 0) {
                bestMinCost_t[v] = minOf(minCostForValue[v], bestMinCost_t[v + 1])
            }
            bestMinCost_prev = bestMinCost_t
        }
    }

    var ans = INF
    for (t in 0..kInt) {
        if (dp[m - 1][n - 1][t] < ans) {
            ans = dp[m - 1][n - 1][t]
        }
    }
    return ans
}
```

