import java.util.PriorityQueue

data class State(val cost: Long, val i: Int, val j: Int, val t: Long)

fun solve(grid: Array<Array<Long>>, k: Long): Long {
    val m = grid.size
    val n = grid[0].size
    val maxValue = 10000

    val allCells = mutableListOf<Triple<Int, Int, Int>>()
    for (i in 0 until m) {
        for (j in 0 until n) {
            allCells.add(Triple(grid[i][j].toInt(), i, j))
        }
    }
    val sortedCells = allCells.sortedBy { it.first }
    val totalCells = m * n
    val lastIndexForValue = IntArray(maxValue + 1)
    var idx = 0
    for (v in 0..maxValue) {
        while (idx < totalCells && sortedCells[idx].first <= v) {
            idx++
        }
        lastIndexForValue[v] = idx
    }

    val dp = Array(m) { Array(n) { LongArray(k.toInt() + 1) { Long.MAX_VALUE } } }
    val pq = PriorityQueue<State>(compareBy { it.cost })
    dp[0][0][k.toInt()] = 0
    pq.add(State(0, 0, 0, k))

    while (pq.isNotEmpty()) {
        val (cost, i, j, t) = pq.poll()
        if (cost != dp[i][j][t.toInt()]) continue

        if (i == m - 1 && j == n - 1) {
            continue
        }

        if (i + 1 < m) {
            val ni = i + 1
            val nj = j
            val ncost = cost + grid[ni][nj]
            val tIndex = t.toInt()
            if (ncost < dp[ni][nj][tIndex]) {
                dp[ni][nj][tIndex] = ncost
                pq.add(State(ncost, ni, nj, t))
            }
        }

        if (j + 1 < n) {
            val ni = i
            val nj = j + 1
            val ncost = cost + grid[ni][nj]
            val tIndex = t.toInt()
            if (ncost < dp[ni][nj][tIndex]) {
                dp[ni][nj][tIndex] = ncost
                pq.add(State(ncost, ni, nj, t))
            }
        }

        if (t > 0) {
            val currentVal = grid[i][j].toInt()
            val endIndex = if (currentVal > maxValue) totalCells else lastIndexForValue[currentVal]
            for (p in 0 until endIndex) {
                val (_, x, y) = sortedCells[p]
                val newT = t - 1
                val tIndex = newT.toInt()
                if (cost < dp[x][y][tIndex]) {
                    dp[x][y][tIndex] = cost
                    pq.add(State(cost, x, y, newT))
                }
            }
        }
    }

    var ans = Long.MAX_VALUE
    for (t in 0..k.toInt()) {
        if (dp[m - 1][n - 1][t] < ans) {
            ans = dp[m - 1][n - 1][t]
        }
    }
    return ans
}
