fun solve(grid: Array<Array<Long>>, k: Long): Long {
    val kk = k.toInt()
    val m = grid.size
    val n = grid[0].size
    val dist = Array(m) { Array(n) { LongArray(kk + 1) { Long.MAX_VALUE } } }
    dist[0][0][0] = 0
    val pq = PriorityQueue<State>(compareBy { it.cost })
    pq.add(State(0, 0, 0, 0))

    while (pq.isNotEmpty()) {
        val (cost, i, j, t) = pq.poll()
        if (cost != dist[i][j][t]) continue

        val moves = arrayOf(0 to 1, 1 to 0)
        for ((dx, dy) in moves) {
            val ni = i + dx
            val nj = j + dy
            if (ni in 0 until m && nj in 0 until n) {
                val ncost = cost + grid[ni][nj]
                if (ncost < dist[ni][nj][t]) {
                    dist[ni][nj][t] = ncost
                    pq.add(State(ncost, ni, nj, t))
                }
            }
        }

        if (t < kk) {
            for (x in 0 until m) {
                for (y in 0 until n) {
                    if (grid[x][y] <= grid[i][j]) {
                        if (cost < dist[x][y][t + 1]) {
                            dist[x][y][t + 1] = cost
                            pq.add(State(cost, x, y, t + 1))
                        }
                    }
                }
            }
        }
    }

    return (0..kk).minOf { t -> dist[m - 1][n - 1][t] }
}
